class ride_validation_handler extends device:
    RiddenEvent<public>:listenable(device_ai_interaction_result) = external {}

    GetAgentStamina<computes>(Agent: agent): float = { return Agent.Stamina }
    GetWildlifeHealth<computes>(Wildlife: wildlife): float = { return Wildlife.Health }

    AttemptRide<decides>(Agent: agent, Wildlife: wildlife): void = {
        # Failable expression: execution continues only if successful
        if (Stamina := GetAgentStamina[Agent]):
            if (Health := GetWildlifeHealth[Wildlife]):
                if (Stamina >= 15.0 and Health > 0.0):
                    RiddenEvent(this, device_ai_interaction_result{
                        Source := Agent,
                        Target := Wildlife,
                        Result := interaction_result.success
                    })
                else:
                    Print("Ride aborted: Insufficient stamina or health.")
            else:
                Print("Error: Failed to retrieve wildlife health.")
        else:
            Print("Error: Failed to retrieve agent stamina.")
    }

