struct<computes> ride_record:
    AgentId: string
    WildlifeId: string
    StartTime: float

class ride_registry_manager extends device:
    RiddenEvent<public>:listenable(device_ai_interaction_result) = external {}

    LoadRegistry<computes>(): map<string, ride_record> = { return map<string, ride_record>{} }
    SaveRegistry<computes>(Data: map<string, ride_record>): bool = { return true }

    RegisterRide<transacts>(Agent: agent, Wildlife: wildlife): void = {
        var RetryCount: int = 0
        var MaxRetries: int = 3

        while (RetryCount < MaxRetries):
            # Failable load operation
            if (Registry := LoadRegistry[]):
                Key := Agent.GetId()
                Registry[Key] := ride_record{
                    AgentId := Key,
                    WildlifeId := Wildlife.GetId(),
                    StartTime := GetGameTime()
                }
                # Failable save operation
                if (Saved := SaveRegistry[Registry]):
                    RiddenEvent(this, device_ai_interaction_result{
                        Source := Agent,
                        Target := Wildlife,
                        Result := interaction_result.success
                    })
                    return
                else:
                    Print("Save failed, retrying...")
            else:
                Print("Load failed, retrying...")
            RetryCount += 1
            Wait(1.0 * RetryCount)
        Print("Max retries exceeded. Ride registration failed.")
    }

