class multi_prop_delta_animation extends prop_animation:
    public function ApplySynchronizedDeltas(Props: array<prop>, Keyframes: array<delta_keyframe>) -> void <transacts>:
        # Validate loop constraint before concurrent application
        ValidateLoopConstraint(Keyframes)

        # Compute and apply deltas concurrently for each prop
        sync:
            for Prop in Props:
                ApplyPropDeltas(Prop, Keyframes)

    function ApplyPropDeltas(Target: prop, Deltas: array<delta_keyframe>) -> void <transacts>:
        CurrentTransform := Target.GetTransform()
        for Delta in Deltas:
            # Concatenate world-space delta to current transform
            DeltaTransform := transform(Delta.translation_delta, Delta.rotation_delta)
            CurrentTransform *= DeltaTransform
            Target.SetTransform(CurrentTransform)

    function ValidateLoopConstraint(Deltas: array<delta_keyframe>) -> void <computes>:
        NetTrans := vector.zero()
        NetRot := quaternion.identity()
        for D in Deltas:
            NetTrans += D.translation_delta
            NetRot *= D.rotation_delta

        if NetTrans.magnitude() > 0.001 or NetRot.angle() > 0.001:
            raise error("Loop constraint violated: net transform is not zero")

