class resilient_delta_applier extends prop_animation:
    public function ApplyBestEffortDeltas(Target: prop, RawDeltas: array<delta_keyframe>) -> void <transacts>:
        # Use rush for best-effort delta computation/application
        AppliedDeltas := rush:
            for RawDelta in RawDeltas:
                ComputedDelta := ComputeSafeDelta[RawDelta]
                if ComputedDelta:
                    return ComputedDelta
                else:
                    return delta_keyframe() # Identity fallback on failure

        # Enforce loop constraint by adjusting the final delta
        FinalDeltas := EnforceLoopClosure(AppliedDeltas)
        ApplyTrackDeltas(Target, FinalDeltas)

    function ComputeSafeDelta(Raw: delta_keyframe) -> optional<delta_keyframe> <computes>:
        # Simulate failable computation (e.g., network latency or math singularity)
        if Raw.translation_delta.magnitude() > 100.0:
            return none
        return Raw

    function EnforceLoopClosure(Deltas: array<delta_keyframe>) -> array<delta_keyframe> <computes>:
        if Deltas.length() == 0:
            return Deltas

        NetTrans := vector.zero()
        NetRot := quaternion.identity()
        for D in Deltas:
            NetTrans += D.translation_delta
            NetRot *= D.rotation_delta

        # Build new array with adjusted last element to close the loop
        var ResultDeltas := array<delta_keyframe>{}
        for I in range(Deltas.length() - 1):
            ResultDeltas.append(Deltas[I])

        LastDelta := Deltas[Deltas.length() - 1]
        LastDelta.translation_delta -= NetTrans
        LastDelta.rotation_delta *= quaternion.inverse(NetRot)
        ResultDeltas.append(LastDelta)
        return ResultDeltas

    function ApplyTrackDeltas(Target: prop, Deltas: array<delta_keyframe>) -> void <transacts>:
        CurrentTransform := Target.GetTransform()
        for Delta in Deltas:
            DeltaTransform := transform(Delta.translation_delta, Delta.rotation_delta)
            CurrentTransform *= DeltaTransform
            Target.SetTransform(CurrentTransform)
